typedef struct {
    int iterations;
    int size;
    double time_ms;
} malloc_benchmark_result_t;

malloc_benchmark_result_t benchmark_malloc(int iterations, int size) {
    benchmark_timer_t timer;
    malloc_benchmark_result_t result = {iterations, size, 0};

    timer_start(&timer);

    for (int i = 0; i < iterations; i++) {
        void *ptr = malloc(size);
        memset(ptr, 0xFF, size);
        free(ptr);
    }

    timer_stop(&timer);
    result.time_ms = timer.elapsed;

    return result;
}

