#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <sys/time.h>
#include <unistd.h>
#include <stdbool.h>

/* ===================== 시간 측정 유틸리티 ===================== */

static inline double get_time_ms(void) {
    struct timespec ts;
    clock_gettime(CLOCK_MONOTONIC, &ts);
    return ts.tv_sec * 1000.0 + ts.tv_nsec / 1000000.0;
}

/* ===================== 메모리 풀 구현 ===================== */

typedef struct pool_node {
    struct pool_node *next;
    uint8_t data[1];  // 유연한 배열
} pool_node_t;

typedef struct {
    pool_node_t *free_list;
    size_t block_size;
    size_t allocated_count;
    size_t freed_count;
    size_t total_allocated;
    uint8_t *memory_base;
    size_t memory_size;
} memory_pool_t;

/* 메모리 풀 초기화 */
memory_pool_t* pool_create(size_t block_size, size_t max_blocks) {
    memory_pool_t *pool = malloc(sizeof(memory_pool_t));
    pool->block_size = block_size + sizeof(pool_node_t);
    pool->allocated_count = 0;
    pool->freed_count = 0;
    pool->total_allocated = 0;
    pool->memory_size = pool->block_size * max_blocks;

    // 전체 메모리를 한 번에 할당
    pool->memory_base = malloc(pool->memory_size);
    pool->free_list = NULL;

    // 프리 리스트에 모든 블록 추가
    for (size_t i = 0; i < max_blocks; i++) {
        pool_node_t *node = (pool_node_t *)(pool->memory_base + i * pool->block_size);
        node->next = pool->free_list;
        pool->free_list = node;
    }

    return pool;
}

/* 메모리 풀에서 할당 */
void* pool_alloc(memory_pool_t *pool) {
    if (!pool->free_list) {
        return malloc(pool->block_size);  // 폴백
    }

    pool_node_t *node = pool->free_list;
    pool->free_list = node->next;
    pool->allocated_count++;
    pool->total_allocated++;

    return node->data;
}

/* 메모리 풀로 반환 */
void pool_free(memory_pool_t *pool, void *ptr) {
    if (!ptr) return;

    // 메모리 범위 확인
    if (ptr >= (void*)pool->memory_base && 
        ptr < (void*)(pool->memory_base + pool->memory_size)) {

        pool_node_t *node = (pool_node_t *)((uint8_t*)ptr - sizeof(pool_node_t));
        node->next = pool->free_list;
        pool->free_list = node;
        pool->freed_count++;
    } else {
        free(ptr);  // 풀 외부 메모리
    }
}

/* 메모리 풀 정리 */
void pool_destroy(memory_pool_t *pool) {
    free(pool->memory_base);
    free(pool);
}

/* ===================== 배치 할당 벤치마크 ===================== */

typedef struct {
    const char *name;
    double malloc_time;
    double pool_time;
    double improvement;
    long long operations;
} allocation_benchmark_result_t;

allocation_benchmark_result_t benchmark_allocation(const char *name, 
                                                   size_t block_size,
                                                   int iterations) {
    allocation_benchmark_result_t result;
    result.name = name;
    result.operations = iterations;

    void **ptrs = malloc(iterations * sizeof(void*));

    /* 표준 malloc 벤치마크 */
    double start = get_time_ms();
    for (int i = 0; i < iterations; i++) {
        ptrs[i] = malloc(block_size);
        memset(ptrs[i], 0xAA, block_size);
    }
    for (int i = 0; i < iterations; i++) {
        free(ptrs[i]);
    }
    result.malloc_time = get_time_ms() - start;

    /* 메모리 풀 벤치마크 */
    memory_pool_t *pool = pool_create(block_size, iterations + 100);

    start = get_time_ms();
    for (int i = 0; i < iterations; i++) {
        ptrs[i] = pool_alloc(pool);
        memset(ptrs[i], 0xBB, block_size);
    }
    for (int i = 0; i < iterations; i++) {
        pool_free(pool, ptrs[i]);
    }
    result.pool_time = get_time_ms() - start;

    pool_destroy(pool);
    free(ptrs);

    result.improvement = result.malloc_time / result.pool_time;

    return result;
}

/* ===================== 배치 처리 최적화 ===================== */

typedef struct {
    int *data;
    int size;
} batch_item_t;

typedef struct {
    double naive_time;
    double batched_time;
    double improvement;
    long long processed_items;
} batch_processing_result_t;

batch_processing_result_t benchmark_batch_processing(int batch_size, int num_batches) {
    batch_processing_result_t result = {0, 0, 0, 0};

    batch_item_t *items = malloc(batch_size * num_batches * sizeof(batch_item_t));
    for (int i = 0; i < batch_size * num_batches; i++) {
        items[i].data = malloc(sizeof(int) * 100);
        items[i].size = 100;
        for (int j = 0; j < 100; j++) {
            items[i].data[j] = i + j;
        }
    }

    /* 순진한 접근 (개별 처리) */
    double start = get_time_ms();
    long long sum = 0;
    for (int i = 0; i < batch_size * num_batches; i++) {
        for (int j = 0; j < items[i].size; j++) {
            sum += items[i].data[j];
        }
    }
    result.naive_time = get_time_ms() - start;

    /* 배치 처리 (캐시 최적화) */
    start = get_time_ms();
    sum = 0;
    for (int b = 0; b < num_batches; b++) {
        for (int i = 0; i < batch_size; i++) {
            batch_item_t *item = &items[b * batch_size + i];
            for (int j = 0; j < item->size; j += 4) {
                sum += item->data[j];
                if (j+1 < item->size) sum += item->data[j+1];
                if (j+2 < item->size) sum += item->data[j+2];
                if (j+3 < item->size) sum += item->data[j+3];
            }
        }
    }
    result.batched_time = get_time_ms() - start;
    result.improvement = result.naive_time / result.batched_time;
    result.processed_items = batch_size * num_batches;

    for (int i = 0; i < batch_size * num_batches; i++) {
        free(items[i].data);
    }
    free(items);

    return result;
}

/* ===================== 캐싱 최적화 ===================== */

typedef struct {
    int key;
    int value;
    int hits;
} cache_entry_t;

typedef struct {
    cache_entry_t *entries;
    int capacity;
    int size;
} simple_cache_t;

simple_cache_t* cache_create(int capacity) {
    simple_cache_t *cache = malloc(sizeof(simple_cache_t));
    cache->entries = malloc(capacity * sizeof(cache_entry_t));
    cache->capacity = capacity;
    cache->size = 0;
    return cache;
}

int cache_get(simple_cache_t *cache, int key) {
    for (int i = 0; i < cache->size; i++) {
        if (cache->entries[i].key == key) {
            cache->entries[i].hits++;
            return cache->entries[i].value;
        }
    }
    return -1;  // 캐시 미스
}

void cache_put(simple_cache_t *cache, int key, int value) {
    if (cache->size >= cache->capacity) {
        // LRU 제거 (간단한 구현: 가장 오래된 엔트리 제거)
        memmove(cache->entries, cache->entries + 1, 
                (cache->size - 1) * sizeof(cache_entry_t));
        cache->size--;
    }

    cache->entries[cache->size].key = key;
    cache->entries[cache->size].value = key * 2;
    cache->entries[cache->size].hits = 0;
    cache->size++;
}

typedef struct {
    double nocache_time;
    double cache_time;
    double improvement;
    long long cache_hits;
    double hit_rate;
} caching_result_t;

caching_result_t benchmark_caching(int cache_size, int num_accesses) {
    caching_result_t result = {0, 0, 0, 0, 0};

    /* 캐시 없이 */
    double start = get_time_ms();
    long long sum = 0;
    for (int i = 0; i < num_accesses; i++) {
        int key = (i % 100) * 13 % 100;  // 약 20% 히트율
        sum += key * 2;
    }
    result.nocache_time = get_time_ms() - start;

    /* 캐시 사용 */
    simple_cache_t *cache = cache_create(cache_size);

    start = get_time_ms();
    sum = 0;
    long long hits = 0;
    for (int i = 0; i < num_accesses; i++) {
        int key = (i % 100) * 13 % 100;
        int cached = cache_get(cache, key);
        if (cached >= 0) {
            sum += cached;
            hits++;
        } else {
            int value = key * 2;
            sum += value;
            cache_put(cache, key, value);
        }
    }
    result.cache_time = get_time_ms() - start;
    result.cache_hits = hits;
    result.hit_rate = (double)hits / num_accesses * 100;

    free(cache->entries);
    free(cache);

    result.improvement = result.nocache_time / result.cache_time;

    return result;
}

